// CROSS-CUTTING CONCERNS handled at Gateway:

// 1. Authentication — once, not in every service
class ApiGateway {
    void handleRequest(Request req, Response res) {
        // Verify JWT token BEFORE routing
        String token = req.getHeader("Authorization");
        if (!jwtService.verify(token)) {
            res.send(401, "Unauthorized");
            return;  // rejected — never reaches service
        }
        // Token valid — extract user info, add to request
        req.setAttribute("userId", jwtService.getUserId(token));
        // Route to service — service trusts userId is valid
        router.route(req, res);
    }
}

