// URL SHORTENER — key design decisions

// SHORT CODE GENERATION:
// Option 1: MD5 Hash — collision risk
String longUrl = "https://example.com/very/long/path";
String hash = MD5(longUrl).substring(0, 7);  // "a1b2c3d"
// Problem: two different URLs could hash to same 7 chars

// Option 2: Auto-increment ID → Base62 (BETTER)
long id = database.autoIncrement();  // 125435
String shortCode = toBase62(125435); // "W7F"
// Guaranteed unique — ID is unique, encoding is deterministic

String toBase62(long id) {
    String chars = "0123456789abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
    StringBuilder sb = new StringBuilder();
    while (id > 0) {
        sb.append(chars.charAt((int)(id % 62)));
        id /= 62;
    }
    return sb.reverse().toString();
}

