// TOKEN BUCKET — allows bursting, most common
class TokenBucket {
    double tokens;
    double maxTokens;
    double refillRate;  // tokens per second
    long lastRefill;

    boolean allowRequest() {
        long now = System.currentTimeMillis();
        double elapsed = (now - lastRefill) / 1000.0;
        tokens = Math.min(maxTokens, tokens + elapsed * refillRate);
        lastRefill = now;

        if (tokens >= 1) {
            tokens -= 1;
            return true;   // allowed
        }
        return false;      // rejected
    }
}

// FIXED WINDOW — simple, has boundary bug
// Redis implementation:
void checkRateLimit(String clientId) {
    String key = clientId + ":" + getCurrentMinute();  // e.g., "user123:202406"
    long count = redis.incr(key);
    if (count == 1) redis.expire(key, 60);  // set TTL on first request
    if (count > 100) throw new RateLimitException();
}
// BUG: minute=0:59 → 100 requests, minute=1:00 → 100 requests
// 200 requests in 2 seconds! Both windows show 100 but...

// SLIDING WINDOW LOG — accurate, memory-intensive
// Uses Redis Sorted Set:
void checkSlidingWindowLog(String clientId) {
    String key = "rate:" + clientId;
    long now = System.currentTimeMillis();
    long windowStart = now - 60_000;  // 1 minute ago

    redis.zremrangebyscore(key, 0, windowStart);  // remove old entries
    long count = redis.zcard(key);                 // count in window
    if (count >= 100) throw new RateLimitException("Rate limit exceeded");
    redis.zadd(key, now, UUID.randomUUID().toString());  // log this request
    redis.expire(key, 61);
}

// DISTRIBUTED RATE LIMITER — Redis as shared state
// Client hits Server 1: Redis incr → count=50 (allowed)
// Same client hits Server 2: Redis incr → count=51 (same Redis)
// Without Redis: Server 1 sees 50, Server 2 sees 1 → allows 200 requests
// With Redis: all servers share same counter → correct limiting

// ALGORITHM COMPARISON:
// Token Bucket:     Allows burst, smooth average,   simple Redis impl
// Leaky Bucket:     No burst, very smooth output,   queue-based
// Fixed Window:     Simplest, boundary vulnerability
// Sliding Window:   Most accurate, high memory (stores all timestamps)

