// ROUTING — check user preferences
void route(NotificationRequest req) {
    String prefKey = "notif:prefs:" + req.getUserId();
    UserPreference pref = cache.get(prefKey);
    if (pref == null) pref = db.getPreference(req.getUserId());

    if (pref.wantsEmail()) emailQueue.publish(req);
    if (pref.wantsPush())  pushQueue.publish(req);
    if (pref.wantsSMS())   smsQueue.publish(req);
}

// DELIVERY WORKER with retry and idempotency:
class EmailWorker {
    void processNotification(NotificationRequest req) {
        // Idempotency: check if already sent
        if (sentLog.exists(req.getNotificationId())) {
            return;  // already delivered — skip duplicate
        }

        String template = templateStore.get(req.getType());
        String body = renderTemplate(template, req.getData());

        for (int attempt = 1; attempt <= 3; attempt++) {
            try {
                sendGrid.send(req.getUserEmail(), body);
                sentLog.mark(req.getNotificationId(), "EMAIL_SENT");
                return;  // success
            } catch (Exception e) {
                if (attempt == 3) {
                    deadLetterQueue.publish(req);  // give up after 3 attempts
                    return;
                }
                // Exponential backoff: wait 2^attempt seconds
                Thread.sleep((long) Math.pow(2, attempt) * 1000);
            }
        }
    }
}

