// TWITTER FEED — key data model
//
// Tweets table: (tweet_id, user_id, content, created_at)
// Follows table: (follower_id, followee_id)
// Timeline cache: Redis hash per user

// FAN-OUT ON WRITE (push) — for normal users
void postTweet(Tweet tweet) {
    // Step 1: Save tweet to Tweets table
    db.save(tweet);

    // Step 2: Get all followers
    List<Long> followerIds = db.getFollowers(tweet.getUserId());

    // Step 3: Push tweet to each follower's timeline cache
    for (Long followerId : followerIds) {
        String key = "timeline:" + followerId;
        redis.lpush(key, tweet.getId());  // add to front (newest first)
        redis.ltrim(key, 0, 799);         // keep only 800 most recent
    }
    // For user with 1000 followers → 1000 Redis writes
    // For celebrity with 10M followers → 10M Redis writes (TOO SLOW!)
}

// FAN-OUT ON READ (pull) — would be used for celebrities
List<Tweet> getTimeline(Long userId, int page) {
    // Get all followees (accounts this user follows)
    List<Long> followeeIds = db.getFollowees(userId);

    // Fetch recent tweets from each followee (expensive!)
    List<Tweet> allTweets = new ArrayList<>();
    for (Long followeeId : followeeIds) {
        allTweets.addAll(db.getRecentTweets(followeeId, 20));
    }

    // Sort by created_at, paginate
    return allTweets.stream()
        .sorted(Comparator.comparing(Tweet::getCreatedAt).reversed())
        .skip(page * 20).limit(20)
        .collect(toList());
    // 1000 followees → 1000 DB queries merged → SLOW for user
}

// HYBRID APPROACH (what Twitter uses):
List<Tweet> getTimelineHybrid(Long userId, int page) {
    // 1. Get precomputed timeline from Redis (fan-out on write for normal users)
    List<Long> tweetIds = redis.lrange("timeline:" + userId, 0, 799);

    // 2. Identify celebrity followees (followers > 1M)
    List<Long> celebFollowees = getFolloweesAboveThreshold(userId, 1_000_000);

    // 3. Fetch celebrity tweets directly (fan-out on read for celebs)
    List<Tweet> celebTweets = new ArrayList<>();
    for (Long celebId : celebFollowees) {
        celebTweets.addAll(redis.get("user:tweets:" + celebId));  // cached
    }

    // 4. Merge precomputed + celeb tweets, sort, return page
    return merge(fetchTweets(tweetIds), celebTweets, page);
}

