// MESSAGE SEND FLOW:
void sendMessage(String fromUser, String toUser, String content) {
    // Step 1: Create message with sequence number
    Message msg = new Message(
        UUID.randomUUID().toString(),  // message_id (idempotency)
        fromUser, toUser, content,
        System.currentTimeMillis(),    // timestamp
        getNextSeqNum(fromUser, toUser) // sequence number for ordering
    );

    // Step 2: Persist message (source of truth)
    db.saveMessage(msg);

    // Step 3: Find which server recipient is on
    String recipientServer = redis.get("presence:" + toUser);

    if (recipientServer != null) {
        // User is ONLINE — deliver via internal API to their server
        internalAPI.deliverToServer(recipientServer, msg);
        // Their server pushes via WebSocket
    } else {
        // User is OFFLINE — mark for later delivery
        db.markPendingDelivery(msg.getId(), toUser);
    }
}

// USER RECONNECTS (offline delivery):
void onUserConnect(String userId, WebSocketSession session) {
    // Register presence
    redis.set("presence:" + userId, myServerId);

    // Fetch undelivered messages
    List<Message> pending = db.getPendingMessages(userId);
    for (Message msg : pending) {
        session.send(msg);
        db.markDelivered(msg.getId());
    }
}

// GROUP CHAT — fan-out via Kafka:
void sendGroupMessage(String groupId, Message msg) {
    db.saveMessage(msg);
    // Publish to Kafka — all chat servers subscribe
    kafka.publish("group:" + groupId, msg);
    // Each chat server consuming this topic:
    // → checks which of its connected users are in this group
    // → pushes message to those users via WebSocket
}

