// QPS ESTIMATION PATTERN:
void estimateQPS() {
    long dailyActiveUsers = 10_000_000;   // 10M DAU
    long requestsPerUserPerDay = 20;      // 20 requests/user/day
    long totalDailyRequests = dailyActiveUsers * requestsPerUserPerDay;
    // = 200M requests/day
    long secondsPerDay = 86_400;          // ~100K for rough estimate
    long avgQPS = totalDailyRequests / secondsPerDay;
    // = 200M / 86400 ≈ 2,315 QPS
    long peakQPS = avgQPS * 3;            // peak is ~3x average
    // = ~7,000 QPS peak
}

