// Even if two concurrent requests from same user arrive:
// First INSERT succeeds
// Second INSERT fails with duplicate key → client ignores → idempotent

// LIKE COUNT — Redis for speed
void likePost(long postId, long userId) {
    try {
        // Write to DB for durability + duplicate prevention
        db.execute(
            "INSERT IGNORE INTO likes (post_id, user_id) VALUES (?,?)",
            postId, userId
        );
        // Only increment Redis if DB insert actually happened
        if (db.affectedRows() > 0) {
            redis.incr("likes:" + postId);  // atomic increment
        }
    } catch (DuplicateKeyException e) {
        // Already liked — do nothing (idempotent)
    }
}

void unlikePost(long postId, long userId) {
    int deleted = db.execute(
        "DELETE FROM likes WHERE post_id=? AND user_id=?",
        postId, userId
    );
    if (deleted > 0) {
        redis.decr("likes:" + postId);
    }
}

// READ like count — always from Redis (fast)
long getLikeCount(long postId) {
    String count = redis.get("likes:" + postId);
    if (count == null) {
        // Cold start — count from DB and cache
        long dbCount = db.queryCount(
            "SELECT COUNT(*) FROM likes WHERE post_id=?", postId
        );
        redis.set("likes:" + postId, dbCount);
        return dbCount;
    }
    return Long.parseLong(count);
}

