// MEDIA PROCESSOR (runs from Kafka consumer)
void processMedia(MediaJob job) {
    byte[] original = s3Client.getObject(job.getS3Key());

    // Generate multiple resolutions
    Map<String, byte[]> resolutions = Map.of(
        "150x150",  imageProcessor.resize(original, 150, 150),
        "600x600",  imageProcessor.resize(original, 600, 600),
