// YOUTUBE VIDEO PIPELINE

// PHASE 1: UPLOAD (resumable)
class VideoUploadService {
    String initiateUpload(long userId, VideoMetadata meta) {
        String uploadId = UUID.randomUUID().toString();
        // Store upload session in Redis with TTL
        redis.hset("upload:" + uploadId,
            "userId", userId,
            "filename", meta.getFilename(),
            "totalSize", meta.getFileSize(),
            "bytesReceived", 0
        );
        redis.expire("upload:" + uploadId, 86400);  // 24h to complete
        return uploadId;
    }

    void uploadChunk(String uploadId, int chunkIndex, byte[] data) {
        // Store chunk to temporary blob storage
        blobStore.putChunk(uploadId, chunkIndex, data);
        redis.hincrby("upload:" + uploadId, "bytesReceived", data.length);
        // If all chunks received → trigger processing
        if (allChunksReceived(uploadId)) {
            kafka.publish("video.processing", new ProcessingJob(uploadId));
        }
    }
}

// PHASE 2: TRANSCODING (parallel)
class VideoTranscoder {
    void transcode(ProcessingJob job) {
        // Assemble chunks into full video
        byte[] rawVideo = assembleChunks(job.getUploadId());

        // Transcode to ALL resolutions IN PARALLEL
        List<CompletableFuture<Void>> futures = List.of(
            CompletableFuture.runAsync(() -> transcodeResolution(rawVideo, "360p")),
            CompletableFuture.runAsync(() -> transcodeResolution(rawVideo, "480p")),
            CompletableFuture.runAsync(() -> transcodeResolution(rawVideo, "720p")),
            CompletableFuture.runAsync(() -> transcodeResolution(rawVideo, "1080p"))
        );

        // Mark 360p available FIRST (fastest to transcode)
        // Higher resolutions appear as they complete
    }

    void transcodeResolution(byte[] video, String resolution) {
        // Split into 6-second HLS segments
        List<byte[]> segments = hlsSegmenter.split(video, 6);
        for (int i = 0; i < segments.size(); i++) {
            String key = String.format("video/%s/%s/segment_%d.ts",
                videoId, resolution, i);
            cdn.upload(key, segments.get(i));
        }
        // Generate HLS manifest (.m3u8 playlist file)
        generateManifest(videoId, resolution, segments.size());
        db.markResolutionAvailable(videoId, resolution);
    }
}

