// FARE CALCULATION
class FareCalculator {
    Money calculateFare(Trip trip) {
        long distanceCents = (long)(trip.getDistanceMiles() * 150);  // $1.50/mile
        long timeCents     = (long)(trip.getDurationMinutes() * 25); // $0.25/min
        long baseFareCents = 200;  // $2.00 base
        long surgeCents    = (long)((distanceCents + timeCents + baseFareCents)
                            * (trip.getSurgeMultiplier() - 1));

        // ALWAYS use integer cents — never double for money!
        long totalCents = baseFareCents + distanceCents + timeCents + surgeCents;
        return new Money(totalCents, Currency.USD);
    }
}

