class PaymentService {
    PaymentResult chargeRider(String tripId, long amountCents, String paymentMethodId) {
        // Idempotency key tied to tripId — unique per trip
        String idempotencyKey = "payment:trip:" + tripId;

        // Check if already processed
        String existing = redis.get(idempotencyKey);
        if (existing != null) {
            return json.deserialize(existing, PaymentResult.class);
            // Return SAME result — do NOT charge again
        }

        // Process payment with Stripe (also supports idempotency keys)
        PaymentResult result = stripe.charge(
            amountCents,
            paymentMethodId,
            "Uber trip " + tripId,
            idempotencyKey  // Stripe deduplicates on their end too
        );

        // Store result (TTL: 7 days to handle late retries)
        redis.setex(idempotencyKey, 604800, json.serialize(result));

        // Persist to payments DB
        db.save(new Payment(tripId, amountCents, result.getChargeId(),
            result.getStatus(), Instant.now()));

        return result;
