// SURGE PRICING SYSTEM

// SURGE CALCULATION (runs every 60 seconds per cell)
class SurgePricingService {
    void recalculateSurge() {
        // Get all active geographic cells
        Set<String> activeCells = redis.smembers("active:cells");

        for (String cellId : activeCells) {
            // Count available drivers in cell
            long availableDrivers = redis.georadius(
                "drivers:available", cellCenter(cellId), 1.5, "km"
            ).size();

            // Count pending requests in cell (last 5 min)
            long pendingRequests = redis.zcount(
                "requests:" + cellId,
                System.currentTimeMillis() - 300_000,
                System.currentTimeMillis()
            );

            // Calculate surge multiplier
            double surgeMultiplier = 1.0;
            if (availableDrivers > 0) {
                double ratio = (double) pendingRequests / availableDrivers;
                if (ratio > 1.5) surgeMultiplier = 1.0 + (ratio - 1.0) * 0.5;
                surgeMultiplier = Math.min(surgeMultiplier, 3.0);  // cap at 3x
                surgeMultiplier = Math.round(surgeMultiplier * 4) / 4.0; // round to .25
            }

            // Store in Redis (60 second TTL)
            redis.setex("surge:" + cellId, 60,
                String.valueOf(surgeMultiplier));
        }
    }
}

