// URL DEDUPLICATION — Bloom filter
// 50B URLs × 10 bytes each = 500GB if stored fully
// Bloom filter: 50B items, 1% false positive rate = ~72GB
// False positive = URL not crawled but Bloom says it was
// Result: occasionally miss a URL but save massive memory
class BloomFilter {
    BitSet bits;
    int[] hashSeeds = {7, 11, 13, 17};

    boolean mightHaveSeen(String url) {
        for (int seed : hashSeeds) {
            if (!bits.get(hash(url, seed) % bits.size())) return false;
        }
        return true;  // possibly seen (small chance of false positive)
    }

    void markSeen(String url) {
        for (int seed : hashSeeds) {
            bits.set(hash(url, seed) % bits.size());
        }
    }
}

