// BM25 RELEVANCE SCORE (better than TF-IDF):
// Score(doc, query) = Σ IDF(term) × TF_normalized(term, doc)
// IDF = log(total_docs / docs_containing_term)
//       → rare terms score higher than common terms
// TF normalized = TF / (TF + k × (1 - b + b × doc_len/avg_doc_len))
//       → normalizes for document length

// PAGERANK (simplified):
// PR(A) = (1-d) + d × Σ PR(B)/L(B)
// where B = pages linking to A, L(B) = number of outgoing links from B
// d = damping factor (0.85) = probability of following a link
// (1-d) = probability of jumping to random page

// Example (3 pages):
// Page A → Page B, Page C
// Page B → Page C
// Page C → Page A
// Iteration 1: PR(A)=0.15, PR(B)=0.225, PR(C)=0.425
// Iteration 2: PR(A)=0.51, PR(B)=0.15, PR(C)=0.34
// ... converges after ~50 iterations

// MULTI-SIGNAL RANKING:
class SearchRanker {
    double score(Document doc, Query query) {
        return 0.30 * bm25Relevance(doc, query) +
               0.25 * pageRank(doc) +
               0.20 * clickThroughRate(doc, query) +
               0.15 * freshnessScore(doc) +
               0.10 * pageSpeedScore(doc);
        // Weights learned by ML, not manually set
    }
}

// DISTRIBUTED KEY-VALUE STORE

// CONSISTENT HASHING + REPLICATION
class KVStore {
    ConsistentHashRing ring;  // nodes placed on hash ring
    int N = 3;  // replication factor
    int W = 2;  // write quorum
    int R = 2;  // read quorum

    void put(String key, byte[] value) {
        List<Node> replicas = ring.getPreferenceList(key, N);
        // Send write to all N replicas in parallel
        List<CompletableFuture<Boolean>> futures = replicas.stream()
            .map(node -> CompletableFuture.supplyAsync(() -> node.write(key, value)))
            .collect(toList());
        // Wait for W acknowledgments (quorum)
        int acks = waitForQuorum(futures, W, timeout=100ms);
        if (acks < W) throw new WriteQuorumException();
    }

    byte[] get(String key) {
        List<Node> replicas = ring.getPreferenceList(key, N);
        // Read from R replicas in parallel
        List<CompletableFuture<VersionedValue>> futures = replicas.stream()
            .map(node -> CompletableFuture.supplyAsync(() -> node.read(key)))
            .collect(toList());
        // Wait for R responses, return highest version
        List<VersionedValue> results = waitForQuorum(futures, R, timeout=50ms);
        return resolveConflicts(results).getValue();
    }
}

// LSM TREE (disk-based stores like Cassandra, RocksDB)
// Write path:
void write(String key, byte[] value) {
    // 1. Write to WAL (Write-Ahead Log) for durability
    wal.append(key, value);
    // 2. Write to in-memory memtable (fast, sorted)
    memtable.put(key, value);
    // 3. When memtable full (~64MB) → flush to SSTable on disk
    if (memtable.size() > THRESHOLD) flushToDisk();
}

// Read path:
byte[] read(String key) {
    // Check memtable first (most recent writes)
    if (memtable.contains(key)) return memtable.get(key);
    // Check SSTables newest to oldest (bloom filter per SSTable)
    for (SSTable sst : sstables.newestFirst()) {
        if (sst.bloomFilter().mightContain(key)) {
            byte[] val = sst.get(key);
            if (val != null) return val;
        }
    }
    return null;  // key not found
}

// QUORUM TRADEOFFS:
// N=3, W=2, R=2: strong consistency (W+R=4 > N=3)
// N=3, W=1, R=1: high availability, eventual consistency (W+R=2 < N)
// N=3, W=3, R=1: strong consistency, slow writes (all replicas must confirm)
// N=3, W=1, R=3: strong consistency, slow reads

// VECTOR CLOCKS — detect and represent conflicts

// Scenario: key "cart:user1" written concurrently on two nodes
// Initial: {D1:0, D2:0, D3:0} (all at version 0)

// Client writes to D1:
// D1 increments: {D1:1, D2:0, D3:0} → value: ["milk"]

// Before D1 replicates, client also writes to D2:
// D2 increments: {D1:0, D2:1, D3:0} → value: ["bread"]

// Now we have two conflicting versions:
// Version A: {D1:1, D2:0} → ["milk"]
// Version B: {D1:0, D2:1} → ["bread"]
// Neither dominates: A[D1]=1 > B[D1]=0 BUT A[D2]=0 < B[D2]=1
// → CONFLICT: both versions returned to client

// Client resolves: merge → ["milk", "bread"]
// New write with merged clock: {D1:1, D2:1, D3:1}

class VectorClock {
    Map<String, Integer> clock = new HashMap<>();

    void increment(String nodeId) {
        clock.merge(nodeId, 1, Integer::sum);
    }

    ConflictResult compare(VectorClock other) {
        boolean thisDominates = true, otherDominates = true;

        Set<String> allNodes = new HashSet<>(clock.keySet());
        allNodes.addAll(other.clock.keySet());

        for (String node : allNodes) {
            int v1 = clock.getOrDefault(node, 0);
            int v2 = other.clock.getOrDefault(node, 0);
            if (v1 < v2) thisDominates = false;
            if (v1 > v2) otherDominates = false;
        }

        if (thisDominates && !otherDominates) return ConflictResult.THIS_WINS;
        if (otherDominates && !thisDominates) return ConflictResult.OTHER_WINS;
        if (thisDominates && otherDominates)  return ConflictResult.EQUAL;
        return ConflictResult.CONFLICT;  // concurrent writes — conflict!
    }
}

// LAST WRITE WINS (simpler, Cassandra approach):
// Every write gets a client-generated timestamp
// On conflict: highest timestamp wins — simple but risky
CREATE TABLE user_cart (
    user_id    UUID,
    item       TEXT,
    written_at TIMESTAMP,  -- used for LWW resolution
    PRIMARY KEY (user_id, item)
) WITH default_time_to_live = 0
  AND compaction = {'class': 'LeveledCompactionStrategy'};
-- Cassandra automatically keeps highest timestamp on conflict

// READ REPAIR:
void read(String key) {
    List<VersionedValue> versions = readFromAllReplicas(key, N);
    VersionedValue latest = versions.stream().max(byVersion()).get();
    // Return latest to client
    // Async: write latest back to any stale replicas
    versions.stream()
        .filter(v -> v.getVersion() < latest.getVersion())
        .forEach(stale -> asyncRepair(stale.getNode(), key, latest));
}

// END-TO-END ENCRYPTION FLOW (simplified Signal Protocol)

// SETUP (happens once per device installation)
class WhatsAppClient {
    KeyPair identityKeys;      // long-term identity key pair
    KeyPair signedPreKey;      // medium-term signed pre-key
    List<KeyPair> oneTimeKeys; // single-use pre-keys

    void register() {
        // Generate all key pairs locally — private keys NEVER leave device
        identityKeys  = Crypto.generateKeyPair();
        signedPreKey  = Crypto.generateKeyPair();
        oneTimeKeys   = generateBatch(100);

        // Upload ONLY public keys to WhatsApp key server
        server.uploadKeys(
            identityKeys.getPublicKey(),
            signedPreKey.getPublicKey(),
            oneTimeKeys.stream().map(KeyPair::getPublicKey).toList()
        );
        // Private keys stored encrypted in device secure storage
    }
}

// FIRST MESSAGE: Alice → Bob
void sendFirstMessage(String message, String recipientId) {
    // Fetch Bob's public keys from server
    PublicKeyBundle bobKeys = server.getPublicKeys(recipientId);

    // X3DH Key Agreement (generates shared secret WITHOUT server knowing it)
    // Uses Alice's identity key + Bob's pre-keys
    byte[] sharedSecret = x3dh.computeSharedSecret(
        myIdentityKeys.getPrivateKey(),
        bobKeys.getIdentityPublicKey(),
        bobKeys.getSignedPreKeyPublicKey(),
        bobKeys.getOneTimePreKeyPublicKey()
    );
    // sharedSecret is IDENTICAL on both devices (math property of Diffie-Hellman)
    // Server NEVER sees sharedSecret

    // Encrypt message with shared secret
    byte[] encrypted = AES_GCM.encrypt(message.getBytes(), sharedSecret);

    // Send encrypted ciphertext to server → server forwards to Bob
    server.sendMessage(recipientId, encrypted);
}

// DOUBLE RATCHET — new key per message (forward secrecy)
// Message 1: key = KDF(sharedSecret + "message_1") → deleted after use
// Message 2: key = KDF(sharedSecret + "message_2") → deleted after use
// Message 3: key = KDF(sharedSecret + "message_3") → deleted after use
// Even if attacker has sharedSecret + captures messages:
// Cannot derive message keys because KDF is one-way
// Cannot decrypt past messages with compromised current key

// GROUP ENCRYPTION:
// Group has symmetric key K (generated by group creator)
// K encrypted with each member's public key and stored on server
// Member joins → downloads K_encrypted_with_their_key → decrypts with private key
// Group messages encrypted with K → any member can decrypt
// New member joining: K rotated (new K distributed to all members)

// ACID DEMONSTRATION — Bank Transfer

// ATOMICITY: all-or-nothing
Connection conn = db.getConnection();
try {
    conn.setAutoCommit(false);  // start transaction

    // Operation 1: debit Alice
    db.execute("UPDATE accounts SET balance = balance - 100 WHERE id = 1");

    // CRASH HERE without atomicity → Alice lost $100, Bob never got it!
    // With atomicity → transaction rolled back, Alice's $100 restored

    // Operation 2: credit Bob
    db.execute("UPDATE accounts SET balance = balance + 100 WHERE id = 2");

    conn.commit();  // both succeed → ATOMIC
} catch (Exception e) {
    conn.rollback();  // either fails → both rolled back
}

// CONSISTENCY: constraints always satisfied
// Database constraint: balance >= 0
ALTER TABLE accounts ADD CONSTRAINT chk_balance CHECK (balance >= 0);
// Without consistency: balance could go negative
// With consistency: transaction violating constraint is rejected

// ISOLATION: concurrent transactions don't interfere
// Two withdrawals from account with $150:
// Thread 1: SELECT balance FROM accounts WHERE id=1  → sees $150
// Thread 2: SELECT balance FROM accounts WHERE id=1  → sees $150 (dirty!)
// Thread 1: UPDATE balance = 150 - 100 = 50
// Thread 2: UPDATE balance = 150 - 100 = 50  (should be $150 - $100 - $100 = -$50!)
// Without isolation: BOTH succeed → account at $50 instead of refusing second withdrawal

// WITH isolation (SERIALIZABLE):
// Thread 1 holds row lock, Thread 2 WAITS
// Thread 1 commits → balance $50
// Thread 2 sees $50 → $50 - $100 = -$50 → violates constraint → REJECTED

// DURABILITY: committed data survives crash
// Write-Ahead Log (WAL) sequence:
// 1. Write change to WAL (durable, sequential write)
// 2. Acknowledge COMMIT to client
// 3. Apply change to data files (async, can lag)
// CRASH after step 2:
// On recovery: replay WAL → data file updated → durability achieved
// Without WAL: crash after commit → data file not updated → data lost

// ISOLATION LEVELS (tradeoff: isolation vs performance):
// READ UNCOMMITTED: sees dirty reads (other tx uncommitted data)
// READ COMMITTED:   no dirty reads, but non-repeatable reads possible
// REPEATABLE READ:  same row reads return same value within tx
// SERIALIZABLE:     strongest, no anomalies, slowest

// ISOLATION LEVEL ANOMALY MATRIX:
// Level              | Dirty Read | Non-Repeatable | Phantom
// READ UNCOMMITTED   |     ✗      |       ✗        |   ✗
// READ COMMITTED     |     ✓      |       ✗        |   ✗
// REPEATABLE READ    |     ✓      |       ✓        |   ✗  (mostly)
// SERIALIZABLE       |     ✓      |       ✓        |   ✓
// ✓ = prevented, ✗ = can occur

// DIRTY READ example:
// T1: UPDATE accounts SET balance=400 WHERE id=1  (balance was 500)
//     --- not yet committed ---
// T2: SELECT balance FROM accounts WHERE id=1  → reads 400 (DIRTY!)
// T1: ROLLBACK  → balance goes back to 500
// T2 made a decision based on 400 which never existed
// FIX: READ COMMITTED → T2 only sees committed data

// NON-REPEATABLE READ:
// T1: SELECT balance FROM accounts WHERE id=1  → 500
// T2: UPDATE accounts SET balance=400 WHERE id=1; COMMIT;
// T1: SELECT balance FROM accounts WHERE id=1  → 400 (changed!)
// T1 sees different values for same row in same transaction
// FIX: REPEATABLE READ → T1 sees snapshot from start of transaction

// PHANTOM READ:
// T1: SELECT COUNT(*) FROM accounts WHERE balance > 1000  → 5
// T2: INSERT INTO accounts VALUES (6, 1500); COMMIT;
// T1: SELECT COUNT(*) FROM accounts WHERE balance > 1000  → 6 (phantom!)
// FIX: SERIALIZABLE → range lock prevents new rows matching predicate

// HOW THEY'RE IMPLEMENTED:
// MVCC (Multi-Version Concurrency Control) — most modern databases
// Instead of locking, keep multiple versions of each row
// Each transaction sees a consistent SNAPSHOT from its start time
// Writers create new versions, readers see old versions
// No read-write contention → much better concurrency than pure locking

// PostgreSQL: REPEATABLE READ uses MVCC snapshots (no phantom reads)
// MySQL InnoDB: REPEATABLE READ uses MVCC + gap locks (prevents phantoms)

// SET TRANSACTION ISOLATION LEVEL in SQL:
SET TRANSACTION ISOLATION LEVEL READ COMMITTED;
BEGIN;
-- all reads in this transaction see only committed data
SELECT * FROM accounts WHERE id = 1;
COMMIT;

// CASSANDRA DATA MODEL — design for queries, not normalization

// Use case: Store user activity events, query by user and time range

// WRONG (relational thinking):
// users table + events table + JOIN
// Cassandra doesn't support cross-partition JOINs efficiently

// RIGHT (query-first modeling):
CREATE TABLE user_activity (
    user_id    UUID,           -- PARTITION KEY → determines node
    event_time TIMESTAMP,      -- CLUSTERING KEY → sort order within partition
    event_type TEXT,
    metadata   MAP<TEXT, TEXT>,
    PRIMARY KEY (user_id, event_time)  -- composite
) WITH CLUSTERING ORDER BY (event_time DESC);  -- newest first

// All activity for user_123 lives on the SAME nodes (same partition)
// Range query: efficiently gets events in time range within that partition
SELECT * FROM user_activity
WHERE user_id = 123e4567-e89b-12d3-a456-426614174000
  AND event_time >= '2024-01-01' AND event_time <= '2024-01-31';
-- This is fast: single partition, sorted by time → sequential scan

// WRITE PATH:
// 1. Client writes to coordinator node (any node)
// 2. Coordinator finds replica nodes via consistent hashing
// 3. Writes to CommitLog (durability)
// 4. Writes to Memtable (fast in-memory)
// 5. Returns ACK to client after W=Quorum replicas confirm
// Memtable → SSTable flush (async, doesn't block writes)

