// KAFKA ARCHITECTURE VISUALIZATION
//
// Topic: "order-events" with 3 partitions, replication factor 3
//
// Partition 0: [offset0: order1] [offset1: order4] [offset2: order7] ...
// Partition 1: [offset0: order2] [offset1: order5] [offset2: order8] ...
// Partition 2: [offset0: order3] [offset1: order6] [offset2: order9] ...
//
// Producer → routes to partition by key:
// order1 (key=userId=A) → hash(A) % 3 = 0 → Partition 0
// order2 (key=userId=B) → hash(B) % 3 = 1 → Partition 1
// All orders from userId=A → always Partition 0 → guaranteed order for A

// PRODUCER:
KafkaProducer<String, Order> producer = new KafkaProducer<>(config);

void publishOrder(Order order) {
    ProducerRecord<String, Order> record = new ProducerRecord<>(
        "order-events",          // topic
        order.getUserId(),       // key → determines partition
        order                    // value
    );
    producer.send(record, (metadata, exception) -> {
        if (exception != null) {
            log.error("Failed to publish order: " + order.getId());
        } else {
            log.info("Published to partition " + metadata.partition() +
                     " at offset " + metadata.offset());
        }
    });
}

// CONSUMER GROUP:
KafkaConsumer<String, Order> consumer = new KafkaConsumer<>(config);
consumer.subscribe(List.of("order-events"));

void consumeOrders() {
    while (true) {
        ConsumerRecords<String, Order> records = consumer.poll(Duration.ofMillis(100));
        for (ConsumerRecord<String, Order> record : records) {
            processOrder(record.value());
            // Kafka tracks offset automatically (auto-commit)
            // Or manually: consumer.commitSync() for exactly-once guarantees
        }
    }
}

// CONSUMER GROUP PARTITION ASSIGNMENT:
// Topic: 6 partitions
// Consumer Group A (Analytics): 2 consumers
//   Consumer A1 → Partitions 0, 1, 2
//   Consumer A2 → Partitions 3, 4, 5
// Consumer Group B (Notifications): 3 consumers
//   Consumer B1 → Partitions 0, 1
//   Consumer B2 → Partitions 2, 3
//   Consumer B3 → Partitions 4, 5
// Both groups independently consume ALL records
// Each group has its own offset tracking

// REPLICATION:
// Partition 0 leader: Broker 1 (handles reads + writes)
// Partition 0 follower: Broker 2 (replicates from leader)
// Partition 0 follower: Broker 3 (replicates from leader)
// If Broker 1 fails → Broker 2 elected as new leader (ISR election)

// AT-MOST-ONCE (fire and forget)
Properties props = new Properties();
props.put("acks", "0");          // don't wait for broker ACK
props.put("retries", "0");       // no retries
KafkaProducer producer = new KafkaProducer(props);
producer.send(record);           // fire and forget
// Consumer commits BEFORE processing:
for (ConsumerRecord record : records) {
    consumer.commitSync();         // commit offset first
    processRecord(record);         // if crash here → message LOST (never reprocessed)
}
// Use case: clickstream analytics, can afford to lose some events

// AT-LEAST-ONCE (default, most common)
props.put("acks", "all");        // wait for all replicas to confirm
props.put("retries", "3");       // retry on failure
props.put("enable.idempotence", "false");  // no dedup → possible duplicates
// Consumer commits AFTER processing:
for (ConsumerRecord record : records) {
    processRecord(record);         // process first
    consumer.commitSync();         // commit after — if crash before commit → reprocess
}
// If producer gets no ACK → retries → broker may have received original!
// → Same message delivered TWICE to consumer
// Handling: make consumer IDEMPOTENT
// e.g., INSERT IGNORE or UPDATE...WHERE not already processed

// EXACTLY-ONCE (most complex)
props.put("enable.idempotence", "true");     // dedup at broker
props.put("transactional.id", "my-producer"); // unique producer ID
KafkaProducer producer = new KafkaProducer(props);
producer.initTransactions();

try {
    producer.beginTransaction();
    // Read from input topic, process, write to output topic — ALL atomic
    ConsumerRecords records = consumer.poll(...);
    for (ConsumerRecord record : records) {
        Result result = process(record);
        producer.send(new ProducerRecord("output-topic", result));
    }
    // Commit consumer offsets AS PART OF the transaction
    producer.sendOffsetsToTransaction(offsets, consumerGroupId);
    producer.commitTransaction();  // atomic: output written + offset committed
} catch (Exception e) {
    producer.abortTransaction();   // rollback everything
}
// If crash: transaction incomplete → rolled back → reprocess from last committed offset
// Broker deduplicates any retried messages via sequence numbers
// Result: message processed exactly once, output written exactly once

// CHOOSING:
// At-Most-Once:   analytics events, logs where loss OK → best performance
// At-Least-Once:  most use cases, consumer must be idempotent → default
// Exactly-Once:   financial, inventory, billing → highest overhead, use when needed

// CONSUMER GROUP REBALANCE
// Initial state: 6 partitions, 2 consumers
// Consumer-1 → P0, P1, P2
// Consumer-2 → P3, P4, P5

// Consumer-3 joins:
// → Rebalance triggered
// → All consumers stop polling temporarily
// → New assignment:
//    Consumer-1 → P0, P1
//    Consumer-2 → P2, P3
//    Consumer-3 → P4, P5
// → All consumers resume with new partitions

// Consumer-1 fails (heartbeat timeout):
// → Rebalance triggered
// → Consumer-1's partitions redistributed:
//    Consumer-2 → P0, P1, P2, P3
//    Consumer-3 → P4, P5
// → Consumer-2 resumes from Consumer-1's LAST COMMITTED offset

// AUTO-COMMIT PITFALL:
Properties props = new Properties();
props.put("enable.auto.commit", "true");      // commit every 5 seconds
props.put("auto.commit.interval.ms", "5000");

KafkaConsumer consumer = new KafkaConsumer(props);
consumer.subscribe(List.of("orders"));

while (true) {
    ConsumerRecords records = consumer.poll(Duration.ofMillis(100));
    // Received records for offsets 10, 11, 12, 13, 14
    for (ConsumerRecord record : records) {
        processOrder(record);  // processes offset 10, 11, 12...
        // CRASH HERE at offset 12 before auto-commit fires!
    }
    // Auto-commit hasn't fired yet (< 5 seconds since last commit)
    // On restart: consumer reads from last committed offset 9
    // → Reprocesses 10, 11, 12 → DUPLICATE PROCESSING
}

// FIX: Manual commit after processing each batch
props.put("enable.auto.commit", "false");  // disable auto-commit

while (true) {
    ConsumerRecords records = consumer.poll(Duration.ofMillis(100));
    for (ConsumerRecord record : records) {
        processOrder(record);
    }
    consumer.commitSync();  // commit AFTER successfully processing ALL records in batch
    // If crash before commit: reprocess batch → duplicates possible
    // But now duplicates are bounded to one batch, not 5 seconds of data
    // Make processOrder() idempotent to handle this safely
}

// IDEMPOTENT CONSUMER:
void processOrder(Order order) {
    // Check if already processed
    if (db.exists("SELECT 1 FROM processed_orders WHERE order_id=?", order.getId())) {
        return;  // already processed → skip
    }
    // Process and mark as done atomically
    db.transaction(() -> {
        fulfillOrder(order);
        db.execute("INSERT INTO processed_orders (order_id) VALUES (?)", order.getId());
    });
}

// KAFKA HIGH THROUGHPUT OPTIMIZATIONS

// 1. SEQUENTIAL WRITES (vs random writes in B-tree)
// B-tree (PostgreSQL, MySQL):
//   Write order_id=1000 → find B-tree node → random disk seek → write
//   Write order_id=2000 → find B-tree node → different random seek → write
//   Throughput: ~100-500 writes/sec on HDD (random I/O limited)

// Kafka log:
//   Write record → append to end of file → NO seek
//   Throughput: ~100,000+ writes/sec (sequential I/O)

// Actual benchmark (spinning HDD):
// Random writes: 100 MB/s
// Sequential writes: 600 MB/s (6x faster!)
// On SSD: random 500 MB/s vs sequential 3 GB/s (6x faster again)

// 2. ZERO-COPY TRANSFER
// Traditional read:
// [Disk] → (DMA) → [Kernel Buffer]
//               → (CPU copy) → [User Space]
//               → (CPU copy) → [Socket Buffer]
//               → (DMA) → [Network]
// = 2 CPU copies + 4 context switches

// Kafka with sendfile():
// [Disk] → (DMA) → [Kernel Buffer]
//               → (DMA) → [Network]
// = 0 CPU copies + 2 context switches
// Result: CPU usage drops dramatically on consumer reads

// Java equivalent:
FileChannel fileChannel = new FileInputStream(file).getChannel();
SocketChannel socketChannel = ...;
fileChannel.transferTo(0, fileChannel.size(), socketChannel);
// This uses sendfile() internally → zero-copy

// 3. BATCHING
// Producer batches records in memory before sending:
props.put("batch.size", "65536");          // 64KB batch size
props.put("linger.ms", "5");               // wait 5ms to fill batch
props.put("compression.type", "snappy");   // compress batch → smaller network

// Without batching: 10,000 records = 10,000 network calls
// With batching: 10,000 records = ~10 network calls (1000 records each)
// Network overhead: fixed cost per call (TCP headers, etc.)
// Batching amortizes this cost across many records

// 4. PAGE CACHE
// Kafka doesn't use JVM heap for caching — relies on OS
// Server with 64GB RAM:
// JVM Kafka broker: uses 6GB heap
// Remaining 58GB → OS page cache → caches hot partition data
// Recent messages almost always served from page cache (RAM speed)
// Result: reads as fast as memory access (~microseconds)

// DECISION GUIDE: Database Queue vs RabbitMQ vs Kafka

// DATABASE QUEUE — simplest, low volume
// Pattern: poll a table for pending jobs
CREATE TABLE job_queue (
    id         BIGINT PRIMARY KEY AUTO_INCREMENT,
    job_type   VARCHAR(50),
    payload    JSON,
    status     ENUM('pending', 'processing', 'done', 'failed') DEFAULT 'pending',
    created_at TIMESTAMP DEFAULT NOW(),
    retry_count INT DEFAULT 0
);
// Worker polls: SELECT * FROM job_queue WHERE status='pending' LIMIT 10 FOR UPDATE SKIP LOCKED
// ✓ Simple, ACID guarantees, enqueue in same transaction as business logic
// ✗ Polling load on DB, doesn't scale to high throughput
// USE WHEN: < 10K jobs/day, need transactional enqueue

// RABBITMQ — routing, push, moderate volume
// Exchange routes to different queues by message type:
public void publishEvent(String eventType, Object payload) {
    // Direct exchange routes by routing key
    rabbitTemplate.convertAndSend(
        "events_exchange",   // exchange
        eventType,           // routing key: "order.created", "payment.failed"
        payload
    );
}
// payment_queue bound to: "payment.*"
// inventory_queue bound to: "order.*"
// "order.created" → goes to inventory_queue
// "payment.failed" → goes to payment_queue
// ✓ Complex routing, push delivery, dead-letter queues, per-message TTL
// ✗ Messages deleted after ACK (can't replay), lower throughput than Kafka
// USE WHEN: task distribution, complex routing, < 50K msg/sec

// KAFKA — high throughput, event log, replay
// Multiple consumer groups each consume ALL messages:
kafka.publish("order.events", order);
// Consumer Group: Analytics → processes ALL orders for dashboards
// Consumer Group: Warehouse → processes ALL orders for fulfillment
// Consumer Group: Notifications → processes ALL orders for emails
// Each group independently tracks its own offset
// ✓ Replay events, millions/sec, multiple independent consumers
// ✗ Complex operations, no per-message routing, higher latency than RabbitMQ push
// USE WHEN: event sourcing, audit log, stream processing, > 50K msg/sec

// QUICK DECISION CHECKLIST:
// Need to replay past events?       → Kafka
// Multiple independent consumers?    → Kafka
// Complex message routing rules?     → RabbitMQ
// Already have DB, low volume?       → DB Queue
// Millions of messages/sec?          → Kafka
// Task distribution to workers?      → RabbitMQ

