// SYNC PATTERN 1: DUAL WRITE (simple but risky)
class ProductService {
    void updateProduct(Product product) {
        db.save(product);           // Step 1: write to PostgreSQL
        elasticsearch.index(product); // Step 2: write to ES
        // RISK: Step 1 succeeds, Step 2 fails → INCONSISTENT!
        // No easy rollback for ES
    }
}

// SYNC PATTERN 2: CDC with Debezium (RECOMMENDED)
// Architecture:
// PostgreSQL → Debezium (reads WAL) → Kafka → ES Sync Service → Elasticsearch
//
// Debezium captures every change:
// INSERT → Kafka event: {op: 'c', after: {id:1, name:'Headphones', price:349}}
// UPDATE → Kafka event: {op: 'u', before: {...}, after: {id:1, price:299}}
// DELETE → Kafka event: {op: 'd', before: {id:1}, after: null}

// ES Sync Consumer:
@KafkaListener(topics = "postgres.public.products")
void syncToElasticsearch(ChangeEvent event) {
    switch (event.getOperation()) {
        case 'c':  // create
        case 'u':  // update
            elasticsearch.index("products", event.getAfter().getId(),
                mapToESDocument(event.getAfter()));
            break;
        case 'd':  // delete
            elasticsearch.delete("products", event.getBefore().getId());
            break;
    }
}
// ADVANTAGE: CDC catches ALL changes including batch DB updates,
// migrations, direct SQL queries — even if app code doesn't know
// ADVANTAGE: If ES is down, Kafka buffers events → catches up automatically
// DISADVANTAGE: slight lag (seconds) between DB write and ES update

// SYNC PATTERN 3: Event-Driven
class ProductService {
    void updateProduct(Product product) {
        db.save(product);  // Step 1: write to DB
        kafka.publish("product.events", new ProductUpdated(product));  // Step 2
    }
}

@KafkaListener(topics = "product.events")
void indexProduct(ProductUpdated event) {
    elasticsearch.index("products", event.getProduct());
}
// ADVANTAGE: decoupled, Kafka buffers if ES is down
// DISADVANTAGE: must publish events consistently from all write paths

