// TRIE DATA STRUCTURE
class TrieNode {
    Map<Character, TrieNode> children = new HashMap<>();
    List<Suggestion> topSuggestions = new ArrayList<>();  // top-K sorted by score
    boolean isEnd = false;
}

class Trie {
    TrieNode root = new TrieNode();

    void insert(String word, int score) {
        TrieNode node = root;
        for (char c : word.toCharArray()) {
            node.children.putIfAbsent(c, new TrieNode());
            node = node.children.get(c);
            // Keep top-10 suggestions at each node (sorted by score)
            updateTopSuggestions(node, new Suggestion(word, score));
        }
        node.isEnd = true;
    }

    List<Suggestion> search(String prefix) {
        TrieNode node = root;
        for (char c : prefix.toCharArray()) {
            if (!node.children.containsKey(c)) return Collections.emptyList();
            node = node.children.get(c);
        }
        return node.topSuggestions;  // already sorted, O(prefix_length)
    }
}

// CACHING LAYER (Redis)
List<String> getTypeahead(String prefix) {
    // Check Redis cache first
    String cacheKey = "typeahead:" + prefix.toLowerCase();
    List<String> cached = redis.get(cacheKey);
    if (cached != null) return cached;

    // Cache miss → query trie service
    List<Suggestion> suggestions = trieService.search(prefix);
    List<String> results = suggestions.stream()
        .map(Suggestion::getText)
        .collect(toList());

    // Cache with TTL (longer TTL for common prefixes)
    int ttl = prefix.length() <= 2 ? 3600 : 300;  // 1hr for 1-2 char, 5min for longer
    redis.setex(cacheKey, ttl, results);
    return results;
}

// CLIENT-SIDE DEBOUNCING:
// Without debounce: "system" → 6 API calls (s, sy, sys, syst, syste, system)
// With 200ms debounce: only fires after user stops typing for 200ms
// User types 'system' quickly → only 1-2 API calls instead of 6

// API call:
function onInput(text) {
    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => {
        fetch('/api/typeahead?q=' + text)
            .then(r => r.json())
            .then(suggestions => displayDropdown(suggestions));
    }, 200);  // wait 200ms before firing
}

