// FORWARD PROXY — client knows, acts for clients
//
// Corporate network:
// Employee → [Forward Proxy] → blocks facebook.com → ✗
//                            → allows github.com → ✓ → Github
//
// Privacy:
// User → [Forward Proxy] → Wikipedia
//         Your IP hidden       Sees proxy IP, not user IP

// REVERSE PROXY — server-side, clients don't know
//
// Users → nginx (reverse proxy) → App Server 1
//                               → App Server 2   (load balancing)
//                               → App Server 3

// NGINX CONFIGURATION EXAMPLE:
// nginx.conf
http {
    # Upstream defines pool of backend servers
    upstream app_servers {
        least_conn;  # load balancing: least connections
        server app1.internal:8080 weight=3;  # gets 3x traffic
        server app2.internal:8080 weight=2;
        server app3.internal:8080 weight=1;
        keepalive 100;  # maintain persistent connections to backends
    }

    server {
        listen 443 ssl;  # HTTPS termination at Nginx
        server_name api.myapp.com;

        # SSL certificates
        ssl_certificate /etc/ssl/myapp.crt;
        ssl_certificate_key /etc/ssl/myapp.key;

        # Cache static files for 30 days
        location /static/ {
            expires 30d;
            add_header Cache-Control "public, immutable";
        }

        # Reverse proxy API requests
        location /api/ {
            proxy_pass http://app_servers;  # forward to upstream pool
            proxy_set_header X-Real-IP $remote_addr;  # pass client IP
            proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
            proxy_connect_timeout 10s;
            proxy_read_timeout 60s;
        }

        # Rate limiting
        limit_req_zone $binary_remote_addr zone=api:10m rate=100r/s;
        location /api/public/ {
            limit_req zone=api burst=20 nodelay;
        }
    }
}

// NGINX handles 10,000+ concurrent connections with 1 worker process
// Apache: 1 thread per connection → maxes at ~1000 concurrent (memory limit)
// Nginx: event loop → handles 10K+ with minimal memory
// Why? Network I/O is async → no need to block a thread waiting for response

