// CIRCUIT BREAKER STATES
//
//  [CLOSED] ──failure threshold exceeded──→ [OPEN]
//     ↑                                         ↓
//     │                              wait period expires
//     │                                         ↓
//     └────────test requests succeed───── [HALF-OPEN]

// IMPLEMENTATION with Resilience4j (Java)
@Service
class PaymentService {
    // Circuit breaker configuration
    CircuitBreakerConfig config = CircuitBreakerConfig.custom()
        .failureRateThreshold(50)          // trip if > 50% fail
        .waitDurationInOpenState(Duration.ofSeconds(60))  // wait 60s before retry
        .permittedNumberOfCallsInHalfOpenState(3)  // test with 3 requests
        .slidingWindowSize(10)             // track last 10 calls
        .build();

    CircuitBreaker circuitBreaker = CircuitBreaker.of("paymentCB", config);

    PaymentResult processPayment(Payment payment) {
        // Decorate the call with circuit breaker
        Supplier<PaymentResult> decoratedCall = CircuitBreaker
            .decorateSupplier(circuitBreaker, () -> callPaymentGateway(payment));

        return Try.ofSupplier(decoratedCall)
            .recover(CallNotPermittedException.class, ex -> {
                // Circuit is OPEN — fail fast with fallback
                log.warn("Circuit open for payment service — using fallback");
                return PaymentResult.queueForRetry(payment);
            })
            .recover(Exception.class, ex -> {
                // Actual failure — circuit breaker records this
                return PaymentResult.failed(payment, ex.getMessage());
            })
            .get();
    }
}

// CASCADING FAILURE PREVENTION:
// WITHOUT circuit breaker:
// 1000 requests to OrderService
// All call PaymentService (which is down)
// All 1000 threads wait 30s timeout
// OrderService thread pool: 1000 threads maxed out
// New requests to OrderService: rejected (thread pool full)
// OrderService DOWN → cascaded failure!

// WITH circuit breaker:
// After 5 payment failures → circuit OPENS
// Next 995 requests: FAIL FAST (< 1ms per request)
// Fallback: queue payment for retry later
// OrderService threads never blocked → stays healthy
// After 60s: circuit HALF-OPEN → test 3 requests
// Payment service recovered → test succeeds → CLOSED
// Normal operation resumes automatically

// KEY METRICS to monitor:
// circuit_breaker_state: CLOSED/OPEN/HALF_OPEN
// circuit_breaker_failure_rate: 0-100%
// circuit_breaker_calls_not_permitted: count of fast-failed calls
// Alert when circuit opens: indicates downstream service issue

// SAGA PATTERN — e-commerce order flow

// CHOREOGRAPHY-BASED (event-driven, no coordinator)
// Step 1: OrderService creates order
class OrderService {
    void createOrder(Order order) {
        db.save(order.withStatus("PENDING"));
        kafka.publish("order.created", order);  // triggers next step
    }

    // COMPENSATION: cancel order if later step fails
    @KafkaListener(topics = "payment.failed")
    void onPaymentFailed(PaymentFailedEvent event) {
        Order order = db.findById(event.getOrderId());
        order.setStatus("CANCELLED");
        db.save(order);
        kafka.publish("order.cancelled", order);  // notify inventory to release
    }
}

// Step 2: InventoryService reacts
class InventoryService {
    @KafkaListener(topics = "order.created")
    void onOrderCreated(Order order) {
        if (canReserve(order)) {
            db.reserve(order);  // local transaction
            kafka.publish("inventory.reserved", order);
        } else {
            kafka.publish("inventory.failed", order);  // triggers compensation
        }
    }

    // COMPENSATION: release reservation if payment failed
    @KafkaListener(topics = "payment.failed")
    void releaseReservation(PaymentFailedEvent event) {
        db.release(event.getOrderId());  // compensating transaction
    }
}

// ORCHESTRATION-BASED (central coordinator)
class OrderSagaOrchestrator {
    void executeSaga(Order order) {
        SagaState state = createSaga(order);

        try {
            // Step 1: Create order
            orderService.createOrder(order);
            state.markStep("ORDER_CREATED");

            // Step 2: Reserve inventory
            inventoryService.reserve(order);
            state.markStep("INVENTORY_RESERVED");

            // Step 3: Process payment
            paymentService.charge(order);
            state.markStep("PAYMENT_PROCESSED");

            // Step 4: Notify user
            notificationService.sendConfirmation(order);
            state.markCompleted();

        } catch (InventoryException e) {
            // Compensation: just cancel order (no inventory reserved yet)
            orderService.cancelOrder(order.getId());

        } catch (PaymentException e) {
            // Compensation: reverse in order (LIFO)
            inventoryService.releaseReservation(order.getId());  // compensate step 2
            orderService.cancelOrder(order.getId());              // compensate step 1
        }
    }
}

// COMPENSATING TRANSACTIONS must be IDEMPOTENT:
// If compensation fails and is retried:
// releaseReservation(orderId) called twice must be safe
// Second call: reservation already released → no-op (don't throw error)
void releaseReservation(String orderId) {
    int rowsUpdated = db.execute(
        "UPDATE reservations SET status='released' WHERE order_id=? AND status='reserved'",
        orderId
    );
    // If already released: rowsUpdated=0 → safe, do nothing
}

